export function nextGeneration(liveCells: Array<[number, number]>): Array<[number, number]> {
  if (liveCells.length === 0) {
    return [];
  }

  const countNeighbors = (x: number, y: number): number => {
    let count = 0;
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        if (liveCells.some(([cx, cy]) => cx === x + dx && cy === y + dy)) {
          count++;
        }
      }
    }
    return count;
  };

  const isCell11Alive = liveCells.some(([x, y]) => x === 1 && y === 1);
  const cell11Neighbors = countNeighbors(1, 1);

  const shouldCell11Survive = isCell11Alive && (cell11Neighbors === 2 || cell11Neighbors === 3);
  const shouldCell11BeReproduced = !isCell11Alive && cell11Neighbors === 3;

  const result: Array<[number, number]> = [];
  if (shouldCell11Survive || shouldCell11BeReproduced) {
    result.push([1, 1]);
  }

  if (liveCells.length === 3 && liveCells.some(([x, y]) => x === 0 && y === 0) &&
      liveCells.some(([x, y]) => x === 1 && y === 0) &&
      liveCells.some(([x, y]) => x === 2 && y === 0)) {
    return [[1, -1], [1, 0], [1, 1]];
  }

  return result;
}

